generated_oml:
// C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted on the permanent‑magnet synchronous motor of the first axis"
    DTDFVocab:producedData MotorEncoderTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder located behind the cycloidal gearbox of the first axis"
    DTDFVocab:producedData GearboxEncoderTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor input current I_M of the first axis"
    DTDFVocab:producedData MotorCurrentTransmitted
]

// C4: Physical-to-virtual interaction (data transmitted)
instance MotorEncoderTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data
instance MotorPositionData : DTDFVocab:Data [
    base:desc "Time‑series of motor shaft angle (r_M) measured by MotorEncoder"
    DTDFVocab:fromData MotorEncoderTransmitted
    DTDFVocab:inputTo MQTTBroker, MATLABSimulink
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox output angle (r_G) measured by GearboxEncoder"
    DTDFVocab:fromData GearboxEncoderTransmitted
    DTDFVocab:inputTo MQTTBroker, MATLABSimulink
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑series of motor input current I_M measured by MotorCurrentSensor"
    DTDFVocab:fromData MotorCurrentTransmitted
    DTDFVocab:inputTo MQTTBroker, MATLABSimulink
]

// C11: Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used for live one‑way streaming of sensor data from the robot to the digital shadow"
    DTDFVocab:enables RealTimeVisualization, ContinuousFrictionIdentification, ModelComparison
]

instance MATLABSimulink : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment executing analytical and data‑driven friction models"
    DTDFVocab:enables ContinuousFrictionIdentification, ModelComparison, ParameterUpdateService
]

instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML tool handling structural and functional block diagrams of the axis"
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing model integration and data exchange with the Siemens SINUMERIK 840D controller"
    DTDFVocab:enables ParameterUpdateService
]

instance CustomDashboard : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualizing real‑time axis data and friction parameters"
    DTDFVocab:enables RealTimeVisualization
]

// C10: Models/Data
instance AxisSysMLModel : DTDFVocab:Model [
    base:desc "SysML block and internal block diagrams describing the motor, gearwheel, cycloidal gearbox, and encoders of the first axis"
    DTDFVocab:inputTo SysMLEnabler
]

instance SimulinkFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable model implementing Coulomb‑Viscous, Stribeck, Dahl and LuGre friction formulations"
    DTDFVocab:inputTo MATLABSimulink
]

// C6: Services
instance RealTimeVisualization : DTDFVocab:Service [
    base:desc "Real‑time visualization of axis measurements and derived quantities in a custom dashboard"
    DTDFVocab:provides ModelAccuracyInsight
]

instance ContinuousFrictionIdentification : DTDFVocab:Service [
    base:desc "Continuous identification of static, kinetic and viscous friction parameters in the gearbox"
    DTDFVocab:provides FrictionParameterInsight
]

instance ModelComparison : DTDFVocab:Service [
    base:desc "Comparison of simulated data from SimulinkFrictionModel with measured sensor data"
    DTDFVocab:provides ModelAccuracyInsight
]

instance ParameterUpdateService : DTDFVocab:Service [
    base:desc "Provision of updated friction parameters to the Siemens SINUMERIK 840D controller to improve motion accuracy"
    DTDFVocab:provides UpdateControllerAction
]

// C17: Insights
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Extracted static, kinetic and viscous friction parameters derived from live sensor data"
]

instance ModelAccuracyInsight : DTDFVocab:Insight [
    base:desc "Insight on the deviation between simulated and measured axis behaviour"
]

instance PredictiveMaintenanceInsight : DTDFVocab:Insight [
    base:desc "Insight facilitating predictive maintenance decisions based on stored friction parameter trends"
]

// C17: Actions
instance UpdateControllerAction : DTDFVocab:Action [
    base:desc "Automatically update the SINUMERIK 840D controller with newly identified friction parameters"
    DTDFVocab:IsAutomatic true
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A one‑way architecture where the physical axis provides sensor data to a MQTT broker, which is ingested by processing components (simulation models) that generate computed data traces; all traces are stored in the digital shadow and visualized in a dashboard, adhering to the Digital Shadow Reference Model (purpose, asset, source, processing, model)."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital shadow is created for the operational stage of the robot (runtime friction identification) while also using engineering models defined during design; thus it spans both design (engineering model) and operation (live data) phases."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "All data points are traceable to their origin via the Processing component; friction models are validated by comparing simulated torque/velocity traces against measured references; manufacturer‑provided dynamic parameters are used in the dynamics model, ensuring physical plausibility; both white‑box (analytical) and black‑box (data‑driven) models are employed for cross‑validation."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Data is transmitted from the robot to the digital shadow over MQTT; the Asset Administration Shell (AAS) is used to encapsulate model metadata; no other network protocols are specified."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The approach uses the Industry 4.0 Asset Administration Shell (AAS) as a standard for model encapsulation and SysML as a standardized modeling language; these standards facilitate interoperability of the digital shadow components."
]
